    localparam bit GenProtocolChecker = 1'b0;

    typedef enum logic [63:0] {
        DebugBase    = 64'h0000_0000,
        ROMBase      = 64'h0001_0000,
        ROM2Base     = 64'h0021_0000, 
        PKTBase      = 64'h0041_0000, 
